#!/bin/bash
# Download all images from ricevillageshops.com
CURL="curl -ksL --ssl-no-revoke --max-time 20"
DIR="$(dirname "$0")"

dl() {
  local url="$1" dest="$2"
  if [ ! -f "$dest" ]; then
    $CURL "$url" -o "$dest" 2>/dev/null && echo "OK: $(basename "$dest")" || echo "FAIL: $(basename "$dest")"
  fi
}

